// ── Tendencia mensual (calculada sobre EVENTS) ─────────────────────────────
export interface MonthlyTrend { month: string; label: string; horasParadas: number; fallas: number; }
const MONTH_LABELS = ["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"];

function buildTrend(events: FailureEvent[]): MonthlyTrend[] {
  const map = new Map<string,{horas:number;fallas:number}>();
  events.forEach(e => {
    const ym = e.fecha.slice(0,7);
    const cur = map.get(ym) ?? { horas:0, fallas:0 };
    cur.horas += e.horasParadas; cur.fallas += 1;
    map.set(ym, cur);
  });
  return Array.from(map.entries()).sort((a,b)=>a[0].localeCompare(b[0])).map(([ym,v])=>{
    const [y,m] = ym.split('-').map(Number);
    return { month: ym, label: `${MONTH_LABELS[m-1]} ${String(y).slice(2)}`, horasParadas: Math.round(v.horas*100)/100, fallas: v.fallas };
  });
}
export const MONTHLY_TREND: MonthlyTrend[] = buildTrend(EVENTS);

export const ESPECIALIDAD_COLORS: Record<Especialidad,string> = {
  "MECÁNICO":  "#B91C1C", // red-700 (principal)
  "ELÉCTRICO": "#DC2626", // red-600
  "SOLDADOR":  "#7F1D1D", // red-900 (más oscuro)
  "MOLDERO":   "#EF4444", // red-500
  "AUTOMOTRIZ":"#FCA5A5", // red-300 (claro)
};

export interface KpiSet {
  horasParadas: number; fallas: number; mtbf: number; mttr: number;
  disponibilidad: number; horasProgramadas: number;
}

function inRange(iso: string, from: Date, to: Date): boolean {
  const t = new Date(iso + 'T12:00:00').getTime();
  return t >= new Date(from.getFullYear(),from.getMonth(),from.getDate()).getTime()
      && t <= new Date(to.getFullYear(),to.getMonth(),to.getDate(),23,59,59).getTime();
}

/** Calcula horas programadas sumando HORAS_PROD filtrado por rango y sub-zonas */
export function computeHorasProgramadas(from: Date, to: Date, subZonas: SubZonaConfig[]): number {
  const allow = new Set(subZonas.map(s => s.name));
  let sum = 0;
  for (const r of HORAS_PROD) {
    if (!allow.has(r.subZona)) continue;
    if (!inRange(r.fecha, from, to)) continue;
    sum += r.horas;
  }
  return sum;
}

export function computeKpis(events: FailureEvent[], horasProgramadas: number): KpiSet {
  const horasParadas = events.reduce((s,e)=>s+e.horasParadas,0);
  const fallas = events.length;
  const horasOperacion = Math.max(0, horasProgramadas - horasParadas);
  const mtbf = fallas > 0 ? horasOperacion/fallas : horasOperacion;
  const mttr = fallas > 0 ? horasParadas/fallas : 0;
  const disponibilidad = horasProgramadas > 0 ? (horasOperacion/horasProgramadas)*100 : 0;
  return { horasParadas, fallas, mtbf, mttr, disponibilidad, horasProgramadas };
}

export function computeKpisBySubZona(events: FailureEvent[], subZonas: SubZonaConfig[], from: Date, to: Date) {
  return subZonas.map(sz => {
    const ev = events.filter(e => e.subZona === sz.name);
    const hp = computeHorasProgramadas(from, to, [sz]);
    const k = computeKpis(ev, hp);
    return { subZona: sz.name, ...k };
  });
}
